xlabel(ax, "Time (hours)"); %[output:26b9ae34]
ylabel(ax, "Probability"); %[output:26b9ae34]
pause(2);
exportgraphics(fig, PictureFolder + filesep + "ServiceTime_histogram.pdf"); %[output:26b9ae34]
